const TURN_ACTIVITY_LIVE_REFRESH_DELAY_MS = 120;
const TURN_ACTIVITY_LIVE_REFRESH_RETRY_DELAY_MS = 1_500;
const TURN_ACTIVITY_LIVE_REFRESH_MAX_ATTEMPTS = 3;
// Minimum spacing between resync_required-triggered full snapshot
// refreshes on the session-list stream. Each full resync is a snapshot
// GET plus a near-immediate stream reopen (ticket mint + auth), so a
// server-side resync storm must not translate 1:1 into client load.
// Inside the window the stream falls back to the backoff-delayed
// reopen without the snapshot fetch; the reopened stream re-signals
// resync_required if a snapshot is still needed once the window has
// elapsed.
const SESSION_LIST_RESYNC_MIN_INTERVAL_MS = 5_000;

type ToolKind = "mcp" | "shell";
// TurnActivityPageInfo (the per-turn /activity page directory) and the rule for
// turning it into a rendered pager live in ./turnActivityPager.

type TurnActivitySummary = {
  turnId?: string;
  turnNumber?: number;
  status?: "active" | "completed" | string;
  active?: boolean;
  toolCount?: number;
  progressNoteCount?: number;
  reasoningCount?: number;
  backgroundTaskCount?: number;
  questionCount?: number;
  errorCount?: number;
  childCount?: number;
  compactedCount?: number;
  compactedEntryIds?: string[];
  startedAt?: string;
  completedAt?: string;
  lastActivityAt?: string;
  startOrderKey?: string;
  endOrderKey?: string;
  sourceEventId?: string;
  submittedSource?: string;
  turnUsage?: unknown;
  usageObservation?: unknown;
  // The model/effort this turn ran on (carried on the shell's activity summary
  // by the backend projection). Lets the Turns surface show each turn's model
  // independent of the composer chip's next-turn selection.
  model?: string;
  effort?: string;
};
type TurnActivityCollapseSummary = {
  collapsible?: boolean;
  defaultCollapsed?: boolean;
  hiddenCount?: number;
  finalAnswerCount?: number;
  reason?: string;
};
export type TranscriptEntry = Omit<SandboxTranscriptEntry, "role" | "kind"> & {
  kind: SandboxTranscriptEntry["kind"] | "background_task" | "turn_activity";
  role?: "user" | "assistant" | "system";
  toolKind?: ToolKind;
  toolServer?: string;
  toolAction?: string;
  transcriptSource?: "server" | "realtime";
  sourceEventId?: string;
  orderKey?: string;
  contentOrderKey?: string;
  activityEndOrderKey?: string;
  localOnly?: boolean;
  turnId?: string;
  turnNumber?: number;
  clientNonce?: string;
  providerItemId?: string;
  display?: UserMessageDisplay;
  startedAt?: string;
  updatedAt?: string;
  completedAt?: string;
  turnTerminalStatus?: "completed" | "failed" | "interrupted";
  turnTerminalAt?: string;
  turnTerminalEventId?: string;
  turnTerminalOrderKey?: string;
  turnUsage?: unknown;
  usageObservation?: unknown;
  attachments?: MessageAttachmentDisplay[];
  // For user-role messages authored by a sibling tank-operator session
  // via the mcp-tank-operator handoff path: the originating session id.
  // RunMessageBubble uses this as an agent-authored signal, but it must
  // not synthesize a local avatar identity from the id.
  originSessionId?: string;
  originSessionAvatarId?: string;
  // For user-role messages submitted by a non-interactive principal (an
  // auth.romaine.life bot token): "system". RunMessageBubble renders the
  // session's system identity for these instead of the human owner's
  // Gravatar. originSessionId takes precedence when both are present.
  authorKind?: string;
  // For user-role message entries: the model/effort this turn was submitted
  // with (the run config the runner pinned for the turn), stamped by the
  // backend submission projection. Lets the Turns surface show which model
  // each turn ran on even after a mid-session model/effort re-pin — the
  // composer chip only reflects the next turn's selected model.
  model?: string;
  effort?: string;
  // Server-projected rows that belong only to the Turns activity surface.
  // Background wake prompts intentionally use role=user + authorKind=system so
  // the renderer shows the existing system-user identity without surfacing the
  // row in the main transcript.
  turnOnly?: boolean;
  wakePrompt?: boolean;
  questionFinalAnswerContext?: boolean;
  backendTurnId?: string;
  turnDetailRole?: "final_answer";
  // metaKind specializes a meta-kind row into a distinguishable transcript
  // surface without growing the shared `kind` enum (which comes from the
  // sandbox-agent SDK). renderItem branches on metaKind before falling
  // through to the generic RunMetaBlock. Server projection sets metaKind on
  // rows it surfaces specially in chat — see transcript_projection.go.
  // background_task_wake is the wake/continuation boundary chip: it renders
  // through the generic RunMetaBlock (title + detail), while the agent-facing
  // wake prompt stays on payload.prompt as audit detail — agent-directed
  // instructions never render in the user's chat voice.
  metaKind?:
    | "awaiting_input"
    | "turn_usage"
    | "context_compacted"
    | "background_task_wake";
  // For `awaiting_input` rows inside Turn activity: the Tank-canonical
  // questions plus the target ids the Turns question page posts to /answer.
  // `answered` is durable — set once a later turn.input_answered event
  // references the question.
  awaitingInput?: {
    askingTurnId: string;
    questionTurnId?: string;
    questionTurnNumber?: number;
    providerItemId: string;
    timelineId: string;
    providerTimelineId?: string;
    questions: unknown[];
    // ExitPlanMode plan-approval pauses carry the plan markdown; rendered on
    // the question page above the Approve/Request-changes question.
    plan?: string;
    questionCount: number;
    questionIndex?: number;
    questionSet?: number;
    answered: boolean;
    // `dismissed` is durable — set once the question turn carries a
    // non-answer terminal (the user stopped instead of answering, or a
    // restart re-ask was superseded by the original answer). The backend
    // 409s answers to a dismissed question; the card must not offer them.
    dismissed?: boolean;
    answers?: Record<string, string[]>;
    annotations?: Record<string, { preview?: string; notes?: string }>;
  };
  questionTarget?: {
    turnId?: string;
    turnNumber?: number;
    page?: number;
    timelineId?: string;
  };
  taskId?: string;
  taskStatus?: ConversationBackgroundTaskStatus;
  taskSummary?: string;
  taskDescription?: string;
  taskError?: unknown;
  taskToolUseId?: string;
  taskCommand?: string;
  taskCwd?: string;
  taskProcessId?: string;
  taskOutput?: string;
  taskExitCode?: number;
  taskDurationMs?: number;
  taskRawItem?: unknown;
  backgroundOnly?: boolean;
  taskKind?: "scheduled_wakeup" | "control_action";
  wakeupStatus?: ScheduledWakeupStatus;
  wakeupDueAt?: string;
  wakeupScheduledAt?: string;
  wakeupPrompt?: string;
  wakeupFiredTurnId?: string;
  wakeupLastError?: string;
  wakeupAttemptCount?: number;
  controlActionStatus?: ControlActionStatus;
  controlActionTool?: string;
  controlActionAction?: string;
  controlActionTarget?: string;
  controlActionRepo?: string;
  controlActionPrNumber?: number;
  controlActionSha?: string;
  lastToolName?: string;
  activity?: TurnActivitySummary;
  activityIds?: string[];
};
type SdkTerminalStatus = "done" | "error" | "stopped";
type LocalRunStatus = "idle" | "running" | "stopping" | "done" | "error";
type SdkTerminalResult = {
  status: SdkTerminalStatus;
  detail?: string;
};
type SdkHistoryRefreshResult = {
  replayed: boolean;
  terminal?: SdkTerminalResult;
  stale?: boolean;
  error?: string;
};
type TranscriptTimelineBody = {
  session_id?: string;
  rows?: unknown[];
  next_cursor?: string;
  prev_cursor?: string;
  live_order_key?: string;
  found_oldest?: boolean;
  found_newest?: boolean;
  read_state?: { last_read_order_key?: unknown } | null;
  activity?: unknown;
  scheduled_background_tasks?: unknown[];
  target_timeline_id?: string;
  target_cursor?: string;
};
// The durable turn directory: the COMPLETE, submission-ordered set of
// turn_activity shells (server_turn_directory_v1). It owns the selectable turn
// set for the Turns view, independent of the bounded /timeline window the chat
// surface pages. `turns` are the same shell rows /timeline returns, so the SPA
// reuses normalizeProjectedTranscriptEntries to build the selector.
type TurnDirectoryBody = {
  session_id?: string;
  turns?: unknown[];
  count?: number;
  latest_turn_number?: number;
  truncated?: boolean;
};
type TurnDirectoryStatus = "idle" | "loading" | "ready" | "error";
type SdkHistoryRefreshSource =
  | "history"
  | "projected-refresh"
  | "visible-reactivation"
  | "resync"
  | "terminal-refresh"
  // User-initiated force-pull of the durable tail via the R shortcut.
  | "keyboard-refresh";
type ScrollToLatestBehavior = "auto" | "smooth";
type ScrollToLatestReason =
  | SdkHistoryRefreshSource
  | "submit"
  | "manual"
  | "keyboard";
type ScrollToLatestRequest = {
  signal: number;
  behavior: ScrollToLatestBehavior;
  reason: ScrollToLatestReason;
  enabled: boolean;
};
type SkillStateName = "test" | "rollout";
type InitialMessageMode =
  | "direct"
  | "diagnose"
  | "bug_report"
  | "quality_gaps"
  | "go_long"
  | "test";
type HomeTab = HomeRouteTab | AppRouteTab;

type ForkSessionRequest = {
  sourceSession: Session;
  forkedEntry: TranscriptEntry;
  model: string;
  // Empty string means the target runner should use its baked-in default,
  // so legacy forks created before this field existed keep working without
  // a migration.
  effort: string;
};

type AppPublicConfig = {
  session_scope?: string;
  spirelens_mcp_available?: string;
  fork_session_prompt_template?: string;
  // Splash-page initial-message mode directives, sourced live from the
  // app-config ConfigMap via /api/config so they can be edited against main
  // without a frontend rebuild. The DEFAULT_INITIAL_MODE_*_DIRECTIVE consts
  // below are the offline fallback when the fetch is empty or fails.
  initial_mode_diagnose_directive?: string;
  initial_mode_bug_report_directive?: string;
  initial_mode_quality_gaps_directive?: string;
  initial_mode_go_long_directive?: string;
  initial_mode_test_directive?: string;
};

