function approvalNotificationTurnId(body: unknown): string {
  if (!body || typeof body !== "object" || Array.isArray(body)) return "";
  const notification = (body as Record<string, unknown>).agent_notification;
  if (
    !notification ||
    typeof notification !== "object" ||
    Array.isArray(notification)
  )
    return "";
  const record = notification as Record<string, unknown>;
  if (record.delivered !== true) return "";
  return typeof record.turn_id === "string" ? record.turn_id.trim() : "";
}

// Deep link to a specific message inside a session. Read by
// readInitialMessageId() on cold start so we can scroll the active
// session's transcript to the referenced entry. Shape mirrors the
// existing ?session= contract so URLs compose cleanly when an agent
// or human pastes one as a shareable pointer.
function messageUrl(
  sessionId: string,
  entryId: string,
  shareToken?: string | null,
): string {
  const url = new URL(window.location.href);
  url.pathname = "/";
  url.search = "";
  url.hash = "";
  url.searchParams.set("session", sessionId);
  url.searchParams.set("message", entryId);
  if (shareToken?.trim()) url.searchParams.set("share", shareToken.trim());
  return url.toString();
}

function readInitialMessageId(): string | null {
  const params = new URLSearchParams(window.location.search);
  return params.get("message") ?? params.get("timeline_id");
}

function clearInitialMessageId(): void {
  const url = new URL(window.location.href);
  url.searchParams.delete("message");
  url.searchParams.delete("timeline_id");
  window.history.replaceState({}, "", url.toString());
}

function sessionListDebugRow(session: Session): SessionListDebugRow {
  const avatar = getSessionAvatarByID(session.agent_avatar_id);
  return {
    id: session.id,
    // name is the server-canonical title now rendered everywhere. Title
    // provenance (user-set vs server-derived) is deliberately not modeled, so
    // the debug row no longer emits a provenance/source distinction.
    name: session.name,
    pod_name: session.pod_name,
    mode: session.mode,
    status: session.status,
    visible: true,
    row_version:
      typeof session.row_version === "number" ? session.row_version : null,
    sidebar_position:
      typeof session.sidebar_position === "number"
        ? session.sidebar_position
        : null,
    agent_avatar_id: session.agent_avatar_id ?? null,
    system_avatar_id: session.system_avatar_id ?? null,
    rendered_avatar_id: avatar?.id ?? null,
    rendered_avatar_src: avatar?.src ?? null,
    rendered_avatar_custom: avatar?.custom === true,
    requested_at: session.requested_at,
    created_at: session.created_at,
    ready_at: session.ready_at,
  };
}

function sessionListDebugRows(
  sessions: readonly Session[],
): SessionListDebugRow[] {
  return sessions.map(sessionListDebugRow);
}

function selectTitleInputText(event: ReactFocusEvent<HTMLInputElement>): void {
  const input = event.currentTarget;
  const select = () => {
    if (document.activeElement === input) input.select();
  };
  select();
  window.requestAnimationFrame(select);
}

function formatRuntime(ms: number): string {
  const minutes = Math.max(0, Math.floor(ms / 60_000));
  if (minutes < 1) return "<1m";
  if (minutes < 60) return `${minutes}m`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h`;
  const days = Math.floor(hours / 24);
  return `${days}d`;
}

function formatBootTime(ms: number): string {
  const seconds = Math.max(0, Math.floor(ms / 1000));
  if (seconds < 1) return "<1s";
  if (seconds < 60) return `${seconds}s`;
  return formatRuntime(ms);
}

function currentSessionSkillState(
  testState?: TestState | null,
  rolloutState?: RolloutState | null,
): SkillStateName | null {
  const testActive = testState?.active;
  const rolloutActive = rolloutState?.active;
  if (!testActive && !rolloutActive) return null;
  if (testActive && !rolloutActive) return "test";
  if (rolloutActive && !testActive) return "rollout";
  return null;
}

interface ComposerCostEstimateProps {
  amountUsd: number | null;
  tokens?: number | null;
  // Provider-observed live context window for the session's model. When > 0,
  // the ctx metric renders as a used/window fraction; otherwise it falls back
  // to the bare used count (or the "--" placeholder). Never a model-assumed
  // default.
  contextWindow?: number;
  // Durable count of context compactions for the session scope. Rendered when
  // session metadata supplies it, including the zero state; sourced from
  // durable row metadata, never inferred from whatever transcript entries the
  // browser happens to hold.
  compactionCount?: number | null;
  tokenScopeLabel?: string;
  placeholder?: boolean;
  scopeLabel?: string;
  title?: string;
}

function ComposerCostEstimate({
  amountUsd,
  tokens,
  contextWindow,
  compactionCount,
  tokenScopeLabel,
  placeholder = false,
  scopeLabel = "session",
  title,
}: ComposerCostEstimateProps) {
  const unavailable = placeholder;
  const safeAmountUsd =
    !unavailable && typeof amountUsd === "number" && Number.isFinite(amountUsd)
      ? Math.max(0, amountUsd)
      : 0;
  const safeTokens = unavailable
    ? null
    : typeof tokens === "number" && Number.isFinite(tokens)
      ? Math.max(0, Math.floor(tokens))
      : 0;
  const safeWindow =
    typeof contextWindow === "number" && Number.isFinite(contextWindow)
      ? Math.max(0, Math.floor(contextWindow))
      : 0;
  const hasCompactionMetric =
    typeof compactionCount === "number" && Number.isFinite(compactionCount);
  const safeCompactions = hasCompactionMetric
    ? Math.max(0, Math.floor(compactionCount))
    : 0;
  const normalizedScope = scopeLabel.trim() || "session";
  const formattedAmount = unavailable
    ? "$--"
    : normalizedScope === "turn"
      ? formatTurnCostUsd(safeAmountUsd)
      : formatComposerCostUsd(safeAmountUsd);
  const label = formattedAmount;
  const tokenLabel =
    safeTokens === null
      ? "--"
      : safeWindow > 0
        ? `${formatCompactTokens(safeTokens)}/${formatCompactTokens(safeWindow)}`
        : formatCompactTokens(safeTokens);
  const sentenceScope = `${normalizedScope.charAt(0).toUpperCase()}${normalizedScope.slice(1)}`;
  const normalizedTokenScope =
    tokenScopeLabel?.trim() || `${normalizedScope} tokens`;
  const tokenSentence =
    safeWindow > 0
      ? `${safeTokens?.toLocaleString() ?? 0} of ${safeWindow.toLocaleString()} context tokens`
      : `${safeTokens?.toLocaleString() ?? 0} ${normalizedTokenScope}`;
  const compactionClause = hasCompactionMetric
    ? `, ${safeCompactions} context compaction${safeCompactions === 1 ? "" : "s"}`
    : "";
  const defaultTitle = unavailable
    ? `Cost estimate appears after token usage is available${compactionClause}`
    : `Estimated API-equivalent ${normalizedScope} token cost from provider usage: ${label} / ${tokenSentence}${compactionClause}`;
  return (
    <span
      className={`run-cost-estimate${unavailable ? " is-placeholder" : ""}${hasCompactionMetric ? " has-compaction-metric" : ""}`}
      aria-label={
        unavailable
          ? `${sentenceScope} cost estimate unavailable${compactionClause}`
          : `Estimated ${normalizedScope} cost ${label}, ${tokenSentence}${compactionClause}`
      }
      aria-disabled={unavailable || undefined}
      title={title ?? defaultTitle}
    >
      <span className="run-cost-estimate-metric run-cost-estimate-metric-tokens">
        <span className="run-cost-estimate-value run-cost-estimate-token-count">
          {tokenLabel}
        </span>
        <span className="run-cost-estimate-label">ctx</span>
      </span>
      {hasCompactionMetric && (
        <>
          <span className="run-cost-estimate-divider" aria-hidden="true" />
          <span className="run-cost-estimate-metric run-cost-estimate-metric-compactions">
            <span className="run-cost-estimate-value run-cost-estimate-compaction-count">
              {safeCompactions}
            </span>
            <span className="run-cost-estimate-label">cmp</span>
          </span>
        </>
      )}
      <span className="run-cost-estimate-divider" aria-hidden="true" />
      <span className="run-cost-estimate-metric run-cost-estimate-metric-cost">
        <span className="run-cost-estimate-value run-cost-estimate-amount">
          {label}
        </span>
        <span className="run-cost-estimate-label">usd</span>
      </span>
    </span>
  );
}

type TokenUsageBadgeTone = "message" | "tool";

export function TokenUsageBadge({
  usage,
  tone = "message",
}: {
  usage: unknown;
  tone?: TokenUsageBadgeTone;
}) {
  const breakdown = tokenUsageBreakdown(usage);
  if (!breakdown) return null;
  const title = tokenUsageBadgeTitle(breakdown, tone);
  return (
    <span
      className="run-token-usage-badge"
      data-tone={tone}
      title={title}
      aria-label={title}
    >
      <CoinsIcon size={11} strokeWidth={2.1} aria-hidden="true" />
      <span className="run-token-usage-total">
        {formatCompactTokens(breakdown.total)}
      </span>
    </span>
  );
}

function tokenUsageBadgeTitle(
  usage: TokenUsageBreakdown,
  tone: TokenUsageBadgeTone,
): string {
  const parts = [
    `${usage.total.toLocaleString()} total tokens`,
    `${usage.input.toLocaleString()} input`,
    `${usage.output.toLocaleString()} output`,
  ];
  if (usage.cachedInput > 0) {
    parts.push(`${usage.cachedInput.toLocaleString()} cached`);
  }
  if (usage.reasoningOutput > 0) {
    parts.push(`${usage.reasoningOutput.toLocaleString()} reasoning`);
  }
  const prefix =
    tone === "tool"
      ? "Current turn token usage; tools do not directly spend model tokens"
      : "Turn token usage";
  return `${prefix}: ${parts.join(" · ")}`;
}

